 35	  const [dataSource] = useK8sWatchResource<V1beta1DataSource>({
 36	    groupVersionKind: DataSourceModelGroupVersionKind,
 37	    name: dataImportCron?.spec?.managedDataSource,
 38	    namespace: dataImportCron?.metadata?.namespace,
 39	  });
