 42	    <Grid hasGutter>
 43	      <GridItem span={5}>
 44	        <DescriptionList className="pf-v6-c-description-list">
 45	          <VirtualMachineDescriptionItem
 46	            // body-content text copied from: https://github.com/kubevirt-ui/kubevirt-api/blob/main/containerized-data-importer/models/V1ObjectMeta.ts#L96
 47	            bodyContent={t(
 48	              'Name must be unique within a namespace. Is required when creating resources, although some resources may allow a client to request the generation of an appropriate name automatically. Name is primarily intended for creation idempotence and configuration definition. Cannot be updated. ',
 49	            )}
 50	            breadcrumb="DataImportCron.metadata.name"
 51	            data-test-id={`${dataImportCron?.metadata?.name}-name`}
 52	            descriptionData={dataImportCron?.metadata?.name}
 53	            descriptionHeader={t('Name')}
 54	            isPopover
 55	            moreInfoURL={documentationURL.NAME}
 56	          />
