 72	            bodyContent={t(
 73	              'Map of string keys and values that can be used to organize and categorize (scope and select) objects. May match selectors of replication controllers and services. ',
 74	            )}
 75	            descriptionData={
 76	              <MetadataLabels
 77	                labels={dataImportCron?.metadata?.labels}
 78	                model={DataImportCronModel}
 79	              />
 80	            }
 81	            onEditClick={() =>
 82	              createModal(({ isOpen, onClose }) => (
 83	                <LabelsModal
