 91	                        },
 92	                      ],
 93	                      model: DataImportCronModel,
 94	                      resource: dataImportCron,
 95	                    })
 96	                  }
 97	                  isOpen={isOpen}
 98	                  obj={dataImportCron}
 99	                  onClose={onClose}
100	                />
101	              ))
102	            }
103	            breadcrumb="DataImportCron.metadata.labels"
104	            data-test-id={`${dataImportCron?.metadata?.name}-labels`}
105	            descriptionHeader={t('Labels')}
106	            isEdit
107	            isPopover
108	            moreInfoURL={documentationURL.LABELS}
109	            showEditOnTitle
110	          />
111	          <VirtualMachineDescriptionItem
112	            // body-content text copied from: https://github.com/kubevirt-ui/kubevirt-api/blob/main/containerized-data-importer/models/V1ObjectMeta.ts#L32
113	            bodyContent={t(
114	              'Annotations is an unstructured key value map stored with a resource that may be set by external tools to store and retrieve arbitrary metadata. They are not queryable and should be preserved when modifying objects. ',
115	            )}
116	            descriptionData={
117	              <DataSourceAnnotations annotations={dataImportCron?.metadata?.annotations} />
118	            }
119	            onEditClick={() =>
120	              createModal(({ isOpen, onClose }) => (
121	                <AnnotationsModal
122	                  onSubmit={(updatedAnnotations) =>
123	                    k8sPatch({
124	                      data: [
125	                        {
126	                          op: 'replace',
127	                          path: '/metadata/annotations',
128	                          value: updatedAnnotations,
129	                        },
130	                      ],
131	                      model: DataImportCronModel,
132	                      resource: dataImportCron,
133	                    })
134	                  }
135	                  isOpen={isOpen}
136	                  obj={dataImportCron}
137	                  onClose={onClose}
138	                />
139	              ))
140	            }
141	            breadcrumb="DataImportCron.metadata.annotations"
142	            descriptionHeader={t('Annotations')}
143	            isEdit
144	            isPopover
145	            moreInfoURL={documentationURL.ANNOTATIONS}
146	          />
147	          <VirtualMachineDescriptionItem
148	            // body-content text copied from: https://github.com/kubevirt-ui/kubevirt-api/blob/main/containerized-data-importer/models/V1ObjectMeta.ts#L84
149	            bodyContent={t(
150	              'Time is a wrapper around time.Time which supports correct marshaling to YAML and JSON.  Wrappers are provided for many of the factory methods that the time package offers.',
151	            )}
152	            breadcrumb="DataImportCron.metadata.creationTimestamp"
153	            descriptionData={<Timestamp timestamp={dataImportCron?.metadata?.creationTimestamp} />}
154	            descriptionHeader={t('Created at')}
155	            isPopover
156	          />
157	          <OwnerDetailsItem obj={dataImportCron} />
158	          <DataImportCronManageDetails
159	            onEditClick={() =>
160	              createModal(({ isOpen, onClose }) => (
161	                <DataImportCronManageModal
162	                  dataImportCron={dataImportCron}
163	                  dataSource={dataSource}
164	                  isOpen={isOpen}
165	                  onClose={onClose}
166	                />
167	              ))
168	            }
169	            dataImportCron={dataImportCron}
170	            dataSource={dataSource}
171	          />
172	        </DescriptionList>
173	      </GridItem>
174	    </Grid>
175	  );
176	};

